// One-shot database restore. SQL is embedded as base64 to bypass tool-call size limits.
import postgres from "https://deno.land/x/postgresjs@v3.4.4/mod.js";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

const SQL_B64 = "";

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response("ok", { headers: corsHeaders });
  try {
    const sql = new TextDecoder().decode(Uint8Array.from(atob(SQL_B64), c => c.charCodeAt(0)));
    console.log("Decoded", sql.length, "chars of SQL");

    const dbUrl = Deno.env.get("SUPABASE_DB_URL");
    if (!dbUrl) return j({ error: "SUPABASE_DB_URL not set" }, 500);

    const sqlClient = postgres(dbUrl, { max: 1, prepare: false });
    try {
      console.log("Executing SQL...");
      await sqlClient.unsafe(sql);
      console.log("Done");
      return j({ success: true, chars: sql.length });
    } catch (e) {
      console.error("SQL error:", e);
      return j({ error: String(e?.message ?? e) }, 500);
    } finally {
      await sqlClient.end();
    }
  } catch (e) {
    return j({ error: String(e?.message ?? e) }, 500);
  }
});

function j(d: unknown, s = 200) {
  return new Response(JSON.stringify(d), { status: s, headers: { ...corsHeaders, "Content-Type": "application/json" } });
}
